mapper.update:
update clazz
name = #{name}, room = #{room}, begin_date = #{beginDate}, end_date = #{endDate}, master_id = #{masterId}, subject = #{subject}, update_time = #{updateTime}
where id = #{id}

mapper.select:
select c.*, e.name masterName, (case when begin_date > now() then '未开班' when end_date < now() then '已结课' else '在读' end) status from clazz c left join emp e on c.master_id = e.id
and c.name like concat('%', #{name}, '%')
and c.begin_date >= #{begin}
and c.end_date <= #{end}
